import {
    Avatar,
    Button,
    Card,
    CardBody,
    CardFooter,
    CardHeader,
    Chip,
    Image,
    Link
} from '@nextui-org/react';

import React from 'react';
import postsarr from '../../data/postsArray';
import { Post } from '../../types/types';

interface Props {
    cname: string;
}

function App({ cname }: Props) {
    const newArr = postsarr
        .map((value) => ({ value, sort: Math.random() }))
        .sort((a, b) => a.sort - b.sort)
        .map(({ value }) => value)
        .slice(0, 11);

    return (
        <>
            {newArr.map((obj: Post, idx) => {
                return (
                    <Card className={`max-w-[340px] ${cname}`} key={idx}>
                        <CardHeader className="justify-between">
                            <div className="flex gap-5">
                                <Avatar
                                    isBordered
                                    radius="full"
                                    size="md"
                                    src={`/resources/images/Communities/${obj.subreddit}/icon.png`}
                                />
                                <div className="flex flex-col gap-1 items-start justify-center">
                                    <h4 className="text-small font-semibold leading-none text-default-600 px-3">
                                        <Link
                                            href=""
                                            color="foreground"
                                            underline="hover"
                                        >
                                            r/{obj.subreddit}
                                        </Link>
                                    </h4>
                                    <h5 className="text-small tracking-tight text-default-400 px-3">
                                        <Link
                                            href=""
                                            color="foreground"
                                            underline="hover"
                                        >
                                            Posted by u/{obj.author}
                                        </Link>
                                        <p>{obj.time}</p>
                                    </h5>
                                </div>
                            </div>
                            <div className="flex gap-3 upvotebtn">
                                <Button size="sm" radius="sm">
                                    <Image
                                        className="imgpost"
                                        src="data:image/png;base64, "
                                    />
                                </Button>
                                <div>
                                    <p className="text-medium bg-red">
                                        {obj.upvotes}
                                    </p>
                                </div>
                                <Button size="sm" radius="sm">
                                    <Image
                                        className="imgpost"
                                        src="data:image/png;base64, "
                                    />
                                </Button>
                            </div>
                        </CardHeader>
                        <CardBody className="px-3 py-0 text-small text-default-400">
                            <div className="postbody">
                                <div className="flex flex-row gap-3">
                                    <p className="text-xl postheading">
                                        {obj.title}
                                    </p>
                                    <Chip
                                        className="text-default-400 font-semibold"
                                        variant="shadow"
                                        style={{
                                            backgroundColor: obj.flair.color,
                                            color: 'white'
                                        }}
                                    >
                                        {obj.flair.title}
                                    </Chip>
                                </div>
                                {obj.src.includes('.png') ||
                                obj.src.includes('.PNG') ||
                                obj.src.includes('.jpg') ||
                                obj.src.includes('.jpeg') ? (
                                    <Image
                                        width={600}
                                        height={350}
                                        alt="NextUI hero Image with delay"
                                        src={obj.src.toString()}
                                    />
                                ) : (
                                    <b>{obj.src.slice(25)} ...</b>
                                )}
                            </div>
                        </CardBody>
                        <CardFooter className="gap-3 postfooter">
                            <div className="flex gap-1">
                                <p className="font-semibold text-default-400 text-small">
                                    <img
                                        alt="comment"
                                        className="imgpost"
                                        src="data:image/png;base64,"
                                    />
                                </p>
                                <p className=" text-default-400 text-small">
                                    2 Comments
                                </p>
                            </div>
                            <div className="flex gap-1">
                                <p className="font-semibold text-default-400 text-small">
                                    <img
                                        className="imgpost"
                                        src="data:image/png;base64, "
                                    />
                                </p>
                                <p className="text-default-400 text-small">
                                    Award
                                </p>
                            </div>

                            <div className="flex gap-1">
                                <p className="font-semibold text-default-400 text-small">
                                    <img
                                        alt="share"
                                        className="imgpost"
                                        src="data:image/png;base64,"
                                    />
                                </p>
                                <p className="text-default-400 text-small">
                                    Share
                                </p>
                            </div>
                            <div className="flex gap-1">
                                <p className="font-semibold text-default-400 text-small">
                                    <img
                                        alt="save"
                                        className="imgpost"
                                        src="data:image/png;base64,"
                                    />
                                </p>
                                <p className="text-default-400 text-small">
                                    Share
                                </p>
                            </div>
                        </CardFooter>
                    </Card>
                );
            })}
        </>
    );
}

export default React.memo(App);
